    generated, stepsLeft = helpers.AppendLeftDelimiter(generated, stepsLeft)

# Continue constrained generation until we encounter the RightDelimiter or run out of steps
while stepsLeft > 0 and not generated.endswith(LeftDelimiter + RightDelimiter):
    if helpers.CanConstrain(generated):
        generated, stepsLeft = helpers.AppendConstrainedStep(prompt, generated, stepsLeft)
    else:
        # Attempt to recover from invalid state
        generated, stepsLeft = helpers.RepairByRetry(prompt, generated, 1, stepsLeft)
        has_rolled_back = True

# Ensure the RightDelimiter is placed after the constrained segment
if stepsLeft > 0 and not generated.endswith(LeftDelimiter + RightDelimiter):
    generated, stepsLeft = helpers.AppendRightDelimiter(generated, stepsLeft)

# Remove the LeftDelimiter and RightDelimiter if they were not properly appended
if generated.startswith(LeftDelimiter):
    generated = generated[len(LeftDelimiter):]
if generated.endswith(RightDelimiter):
    generated = generated[:-len(RightDelimiter)]

return generated, stepsLeft

